import{_ as r,o,c as n,a1 as a}from"./chunks/framework.BX4nIuL2.js";const p=JSON.parse('{"title":"概况","description":"","frontmatter":{},"headers":[],"relativePath":"courses/mobile-robot/概况.md","filePath":"courses/mobile-robot/概况.md"}'),i={name:"courses/mobile-robot/概况.md"};function d(s,t,l,e,g,b){return o(),n("div",null,[...t[0]||(t[0]=[a('<h1 id="概况" tabindex="-1">概况 <a class="header-anchor" href="#概况" aria-label="Permalink to &quot;概况&quot;">​</a></h1><p><strong>颜色说明：</strong></p><p>- 普通字体 = v6deepseek框架内容（黑色）</p><p>- 蓝色字体 = v3原始内容</p><p>- 红色字体 = v3与v6冲突内容+建议</p><p>- 删除线 = 建议可删除的内容（保留供人工决策）</p><h1 id="主题-教给孩子ai时代的生存逻辑-培养ai时代的科创人才" tabindex="-1">主题：教给孩子AI时代的生存逻辑，培养AI时代的科创人才 <a class="header-anchor" href="#主题-教给孩子ai时代的生存逻辑-培养ai时代的科创人才" aria-label="Permalink to &quot;主题：教给孩子AI时代的生存逻辑，培养AI时代的科创人才&quot;">​</a></h1><h1 id="概况-1" tabindex="-1">概况 <a class="header-anchor" href="#概况-1" aria-label="Permalink to &quot;概况&quot;">​</a></h1><p><strong>时代之变（Why）：</strong> 2023年人类步入 AI 原生时代，传统的编程与制造门槛正被全面降维。未来科技人才的核心壁垒，不再是死记硬背的底层语法和机械接线，而是定义真实需求、驾驭 AI 工具进行系统性决策的能力。</p><p><strong>方法之新（How）：</strong> 本课程独创性地融合<strong>开源造物精神（FabLab）、项目式学习（PBL）与工业级 AI 敏捷工作流</strong>。通过“硬件统一，AI 赋能”的超级工程放大器，赋能学生跨越跨学科技术鸿沟，完成从“工具使用者”到“物理世界创造者”的蜕变。</p><p><strong>成果之硬（What）：</strong> 课程以国家高素质科创人才鉴定标准为导向。通过对比 3 种以上 AI 方案、BOM 成本优化和 DFM 审查，引导学生打造出打通“端-网-云”的具身智能机器人以及工业级开源作品集，为国内强基综评与海外顶尖名校申请做储备。</p><h2 id="核心" tabindex="-1">核心 <a class="header-anchor" href="#核心" aria-label="Permalink to &quot;核心&quot;">​</a></h2><p>在这个过程中参与者一起在解决工程问题，从而培养能力**：需求提出与定义，AI工具使用与工程化，辩证思考与决策，了解AI能力边界，文档复盘**</p><ul><li><p>角色定位：<strong>从“技术学习者”到“项目决策者”</strong>：AI 降维了跨学科的技术门槛，让学生从“学代码语法”变成“做产品解决真实问题” 。我们绝不教授任何需要死记硬背的语法公式或琐碎接线，而是通过自然语言、大模型编译和参数化设计平台，引导学生直接调动工业级硬件，完成从工具使用者到物理世界创造者的蜕变 。</p></li><li><p>师资重塑：**从“知识灌输者”到“提示词导师”：**在本课程中，教师的角色发生了根本性颠覆。教师不再是一味灌输底层机械或电子细节的传统讲师，而是转型为“提示词导师” 。核心教学目标是教导学生在 AI 时代如何正确、高效地向机器提问，并陪伴他们将大模型的在线生成勇敢地在物理世界中落地 。</p></li><li><p>敏捷形态：**从“传统编组”到“精锐双人组 + AI 智能体”，**课程首创“双人精锐组 + 第三队员 AI Agent”的敏捷开发形态。其底层逻辑基于现代软件工程的“结对编程”与硬件工业界的“敏捷硬件开发”。AI 工具不再是偶尔查资料的辅助软件，而是作为团队不可或缺的超级全栈执行员，让学生深刻体会项目协作的真实生态 。</p></li><li><p>核心教学法：**以“硬件统一，AI 赋能”跨越技术鸿沟，**我们坚信 AI 并非一门独立的理论学科，而是工程落地的超级放大器 。课程通过统一且标准化的硬件平台，将提示词工程、AI 编译、文生图及多智能体系统深度嵌入到机械、电子、算法和产品管理中，让学生能够直接进行系统级集成。</p></li><li><p>成果交付：从“跑通技术 Demo”到“硬核商业作品集”，最终产出的不是简易的玩具，而是打通了“端-网-云-虚拟仿真”的具身智能移动机器人 。学生必须通过 3 种以上的 AI 方案对比、BOM 成本优化和 DFM（可制造性设计）审查来做出关键决策，最终交付包含完整技术拓扑图、GitHub 开源仓库和定量分析图表的硬核作品集</p></li></ul><h2 id="差异对比" tabindex="-1">差异对比 <a class="header-anchor" href="#差异对比" aria-label="Permalink to &quot;差异对比&quot;">​</a></h2><p>与传统教育的区别为以下</p><ul><li><p>禁止行为（绝对不允许出现）</p><ul><li><p>·❌ &quot;今天我们来学习Python语法，然后写一个控制机器人的代码&quot;</p></li><li><p>❌ &quot;大家打开Fusion 360，跟着我画一个底盘模型&quot;</p></li><li><p>❌ &quot;这个电路的原理是这样的，大家按照这个图接线&quot;</p></li></ul></li><li><p>标准行为（必须严格执行）</p><ul><li><p>✅ &quot;你的机器人需要实现自动避障功能，现在告诉AI你的需求，它会给你3种避障方案&quot;</p></li><li><p>✅ &quot;AI已经生成了3个底盘模型，你需要从稳定性、重量、美观度三个维度选一个最好的&quot;</p></li><li><p>✅ &quot;AI已经画好了电路图并生成了接线教程，你按照教程接线，有问题直接问AI&quot;</p></li></ul></li></ul><h2 id="招生学员画像" tabindex="-1">招生学员画像 <a class="header-anchor" href="#招生学员画像" aria-label="Permalink to &quot;招生学员画像&quot;">​</a></h2><ul><li><p><strong>基础门槛：</strong> 具备一定的英语、科学、基础编程或机器人操作经验。</p></li><li><p>年龄：初一，初二，高一，高二</p></li><li><p><strong>核心兴趣：</strong> 对人工智能、具身智能、产品创新及硬核科技竞赛有浓厚探索欲的初高中生。</p></li><li><p><strong>核心诉求：</strong> 有国内升学（强基计划、综合评价、科创特长）或海外顶尖名校申请需求，渴望建立一套含金量极高、真正符合工业标准的个人项目作品集。</p></li></ul><h2 id="关于sophilab" tabindex="-1">关于sophilab <a class="header-anchor" href="#关于sophilab" aria-label="Permalink to &quot;关于sophilab&quot;">​</a></h2><p><img src="https://internal-api-drive-stream.feishu.cn/space/api/box/stream/download/authcode/?code=MjljMGFjZjg4MDRmYTgyMjdiNGZlZDliZjZkYTg1MmZfNjhlNTQ3ZTczYmU1YzNhN2EwYmUwODgzNjMwZTZiYzhfSUQ6NzY0NjIyODQ1NzI3NzYzOTYwOF8xNzgwNDE3NDY4OjE3ODA1MDM4NjhfVjM" alt="Image"></p><p><img src="https://internal-api-drive-stream.feishu.cn/space/api/box/stream/download/authcode/?code=YWUwNzMwYzMyZjQ5MzU2ZTFmMDY1ZTJmMjYxN2YwYmFfMjIyMzE2YjE3NDU4ZDhmMmIyMzk0NmM4NGFmMWUwOGFfSUQ6NzY0NjIyODM2MzQ3MjE5NDUyNl8xNzgwNDE3NDY4OjE3ODA1MDM4NjhfVjM" alt="Image"></p><h1 id="课程大纲" tabindex="-1">课程大纲 <a class="header-anchor" href="#课程大纲" aria-label="Permalink to &quot;课程大纲&quot;">​</a></h1><h2 id="初中组-ai机器人产品体验营" tabindex="-1">初中组：AI机器人产品体验营 <a class="header-anchor" href="#初中组-ai机器人产品体验营" aria-label="Permalink to &quot;初中组：AI机器人产品体验营&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>日期与主题</strong></th><th><strong>内容（上午，下午，工具，产出）</strong></th></tr></thead><tbody><tr><td>第一天： 问题挖掘</td><td><strong>上午</strong><br>- 主题分享机制： FabLab 精神、AI时代跨学科教育及软硬件全新开发流程，引导学生以产品经理思维定义移动机器人；<br>- 需求头脑风暴： 学生自主列出校园、家庭或社区中真实存在的 10 个不便问题（100%学生决策）；指挥 AI 针对校园场景拓展生成 30 个潜在不便问题清单（100% AI执行）；<br>- 痛点深度剖析： 讨论并投票选出 5 个最有价值的问题，运用“用户-场景-痛点”模板进行解构；由 AI 对应生成精准的用户画像与具体场景描述。<br><strong>下午</strong><br>- 精锐团队组建： 明确“双人精锐组”为最小研发单元并完成现场组建，同步进行飞书项目管理工具入门； <br>- 核心问题定型： 团队进行最终决策，砍掉冗余诉求，确立 1 个核心要解决的工程问题；指挥 AI 针对该问题检索并生成* 市面现有竞品的优缺点对比分析；<br>- 产品概念初探： 学生定义产品的核心功能目标；由 AI 辅助进行 Prompt 角色约束、起名、撰写 Slogan 及产品核心定位建议，并初步开展文生图外观脑暴。 <br><strong>工具</strong><br>- 通义千问 / Kimi / DeepSeek / MiniMax / 豆包 ；<br>- 协同协同： 飞书文档、看板 <br><strong>产出</strong><br>小组问题分析报告，创意脑暴海报， 基础 PRD（产品需求文档）草稿、飞书敏捷看板任务分解图，与联合国可持续发展目标对接的 SDG 关联分析表</td></tr><tr><td>第二天： 功能定义</td><td><strong>上午</strong><br>- 模块化认知体系： 了解机器人核心部件，学生学习“每个部件能做什么”，无需懂底层原理（100%学生决策）；<br>- 提示词工程进阶： 学习提示词三要素（目标、要求、约束）以掌握高效向 AI 提需求的技巧；由 AI 针对性生成 5 个提示词场景练习题供学生实战训练。 <br>- 概念外观与生图迭代： 学生自主描述产品外观（颜色、形状、大小、材质）并手绘草图；指挥 AI 连续进行 3 次以上的文生图交互迭代，生成 5 张不同风格的机器人概念效果图。 <br><strong>下午</strong><br>- 用户行为流定义： 学生描述用户使用流程（如启动、工作、停止等交互逻辑）；指挥 AI 自动生成标准的产品用户使用流程图。 <br>- 硬件方案决策： 学生明确机器人功能目标并审核 AI 的推荐方案；由 AI 智能体根据功能需求生成最优硬件选型清单。 <br>- 敏捷角色与看板分工： 了解现代软硬件工程团队的开发角色与进入顺序；由 AI 根据 12 天营期自动匹配生成项目甘特图和敏捷任务清单。 <br>- PRD 定型与环境部署： 学生深度审核、修改并确认 AI 编写的 PRD 初稿，完善用户需求、使用场景与技术约束；同时在 AI 指导下部署极简开发环境（VSCode/lingma），利用自然语言编程（Vibe Coding）快速生成团队与项目介绍网页并发布。 <br><strong>工具</strong><br>- AI 创作端： 大模型（DeepSeek/Kimi/Qwen等）、文生图工具、AI 视频/图文生成智能体。 <br>- 工程开发： VS Code、Gitee/github <br>- 协作管理： 飞书文档、飞书项目敏捷看板。 <br><strong>产出</strong><br>工业级标准最终版 PRD 文档，包含设计文件（ 提示词练习作业、机器人外观概念图、用户使用流程图） ，和工程文档（ 硬件选型清单、飞书项目看板），通过飞书文档生成web</td></tr><tr><td>第三天：<br>参数化结构设计与数字制造</td><td><strong>上午</strong> <br>- <strong>设计规范导临：</strong> 进行创客实验室安全培训，学习工业级 CMF（颜色、材质、工艺）与 DFM（可制造性设计）基础规范，理解“为加工而设计”的原则；<br>- <strong>结构体系认知：</strong> 建立对机器人空间机械结构的感性认知；指挥 AI 快速生成手办及结构概念示意；<br>- <strong>参数化建模决策：</strong> 理顺建模工具冲突，通过sophicar.com进行移动机器人的参数化设计；<br><strong>下午</strong><br>- <strong>三维模型终审：</strong> 学生从结构稳定性、整机重量、美观度三个维度对 AI 方案进行横向对比与关键选型决策；<br>- <strong>数字化加工实操：</strong> 操作数字制造设备，使用 FDM 3D 打印机、激光切割机等，将 AI 导出的最终模型文件加工转化为通电可用的物理实物零件。 <br><strong>工具</strong><br>- <strong>模型生成：</strong> sophicar.com、Fusion 360 AI 脚本；<br>- <strong>三维渲染：</strong> 腾讯混元、Tripo 3D、MakerLab 等 AI 三维生成工具； <br>- <strong>数字加工：</strong> FDM 3D 打印机、激光切割机，激光雕刻机。 <br><strong>产出</strong><br>- <strong>数字资产：</strong> 包含 <code>.stl</code> 等标准格式的最终三维底盘结构模型文件；<br>- <strong>工程文件：</strong> 数字化制造应用探索与加工参数生成文档；<br>- <strong>实物成果：</strong> 加工完成的物理机器人外壳与底盘硬件</td></tr><tr><td>第四天：嵌入式基础</td><td><strong>上午</strong><br>- <strong>电路与引脚认知：</strong> 建立对开源硬件（以 ESP32-S3 为核心）的全局认知，学习 I/O 与引脚定义。学生专注于“学看图、懂逻辑”，不涉及死记硬背的电路原理教学（100%学生决策；指挥 AI 动态生成趣味电路科普视频，讲解硬件工作原理（100% AI执行）。 <br><strong>下午</strong><br>- <strong>敏捷仿真与接线：</strong> 学生借助 AI 生成的图文接线教程与动态引脚映射图，在 Wokwi 虚拟仿真平台中先行完成接线验证；随后在物理实体上操作开源硬件与外围电路（如 CAN 总线或基础驱动模块），完成小车底盘的物理安全接线。 <br>- <strong>自然语言控制开发：</strong> 彻底杜绝传统代码语法教学。学生直接使用自然语言描述机器人的基础运动需求（如前进、转向、LED 状态反馈等；由 AI 纯生成基础运动控制逻辑与控制固件，学生通过图形化或自然语言平台进行审核、一键编译与烧录运行。 <br>- <strong>AI 故障排查：</strong> 通电联调中遇到电机不转等问题，学生直接将硬件异象描述给机器；由 AI 实时生成结构化的故障排查指南，引导学生精准定位接线或调校问题。 <br><strong>工具：</strong><br>- <strong>编译与仿真平台： Aily Blockly ，Wokwi 虚拟仿真平台；</strong><br>- <strong>视觉与多媒体：</strong> Seedance（AI 视频生成）、AI 图文生图工具； <br>- **硬件平台：**核心开源硬件（ESP32-S3 核心板、CAN 外围电路、驱动模块、LED 单元）；<br><strong>产出：</strong><br>- **设计文件：**Wokwi 在线接线仿真模型， <strong>ESP32-S3 prompt和代码</strong><br>- <strong>实物成果：</strong> <strong>第一台可通电运行的物理样机</strong></td></tr><tr><td>第五、六天<br>基础软硬件调试</td><td><br><strong>第一天</strong><br>- <strong>整机机械总装：</strong> 学生推进结构件装配与硬件集成，动手安装外壳与传感器支架；指挥 AI 针对个性化改装生成专属的“一步步外壳与支架数字化装配教程”； <br>- <strong>多外设硬件装配：</strong> 学生自主进行摄像头、超声波传感器等外设的定位与物理部署；由 AI 全自动生成对应的外设驱动底层代码，确保摄像头等器件通电正常运行并进行初步功能测试； <br>- <strong>工业级工艺优化：</strong> 聚焦产品化美感，学生动手对凌乱的电路进行整理与车身美化；指挥 AI 智能体生成标准理线教程，坚决杜绝“飞线”，完成工业级线束收纳。 <br><strong>第二天</strong><br>- <strong>深度控制逻辑重构：</strong> 学生通过自然语言描述深层控制需求（如主控接受传感信号、多传感器融合、优化信号处理等；由 AI 纯执行编译出整车综合控制逻辑； <br>- <strong>多总线通信调优：</strong> 学生审核并部署由 AI 自动编写的嵌入式通信协议层，跑通主控板与电机、舵机控制器之间的 CAN 总线通信与高频串口通信；<br><strong>工具</strong><br>- <strong>AI 协同开发：</strong> vscode、** Aily Blockly；**<br>- <strong>工程调测设备：</strong> 通用螺丝刀及理线模块套装、万用表、可调电源供应器；<br>- <strong>嵌入式总线：</strong> ESP32、CAN 总线扩展模块、串口驱动器。 <br><strong>产出：</strong><br>- <strong>数字资产：</strong> 由 AI 协同生成的车辆深层避障控制算法 ； <br>- <strong>工程文档：</strong> 机器人专属全功能硬件测试报告、故障排查与结构微调日志； <br>- <strong>实物成果：</strong> <strong>外观整洁完整、工艺对齐工业级规格、打通全系统软硬件集成的完整避障机器人</strong>及全功能演示短视频；</td></tr><tr><td>第七天<br>全栈 Vibe Coding</td><td>上午<br>- <strong>零代码界面构建：</strong> 彻底跳过繁琐的 UI 代码编写，学生通过纯自然语言与 AI 对话进行全栈 Vibe Coding（100%学生决策）；指挥 AI 自动编译出美观的 HTML 网页或小程序交互控制界面，包含前进、后退、左转、右转和停止按钮（100% AI执行）。 <br>下午<br>- <strong>跨网控制控制链搭建：</strong> 学生将编译好的界面部署上线，通过蓝牙或 Wi-Fi 协议将网页端与机器人主控板进行跨网桥接。 <br>- <strong>全模块功能集成点接入：</strong> 在网页中接入 AI 对话节点，实现“页面物理按键”与“自然语言指令”的双重控制，测试无线操控的稳定性与响应时延。 <br><strong>工具：</strong><br>- <strong>界面编译：</strong> VS Code 插件、HTML5/CSS/JavaScript 零代码生成器。 <br>- <strong>通信协议：</strong> 本地 Wi-Fi 通信模块、蓝牙 BLE 桥接组件。 <br><strong>产出：</strong><br>- <strong>数字资产：</strong> 跨平台前端控制网页/小程序全套源码包、AI 对话控制接口配置文档。 <br>- <strong>实物成果：</strong> <strong>成功实现 HTML/小程序跨网无线控制的移动机器人交互终端</strong>。</td></tr><tr><td>第八天<br>交互</td><td>视觉/语音与移动机器人，让机器人智能起来<br>描述完整的产品多模态工作流需求（100%学生决策）；指挥 AI 将语音控制、视觉识别、基础网页控制及避障算法代码深度合并，全自动生成单一、完整的集成系统代码，实现“听到指令出发、看到特定障碍物精准刹车/倒垃圾”的智能化作业逻辑（100% AI执行）</td></tr><tr><td><strong>第九天</strong><br>数字孪生<br></td><td><strong>上午</strong><br>- <strong>数字孪生概念认知：</strong> 理解现代工业界“虚拟仿真 $\\rightarrow$ 实体部署”的系统集成方法（100%学生决策）；由 AI 纯执行驱动虚拟仿真平台，生成高精度 3D 虚拟车模型。 <br><strong>下午</strong><br>- <strong>虚实双向高维联动：</strong> 学生通过前端界面的图形化滑块向系统下发控制指令；通过 AI 协助部署的高频双向同步逻辑，实现“滑块调整 $\\rightarrow$ 物理实物运动 $\\rightarrow$ 3D 虚拟车屏幕动画同步”的实时双向演示。 <br><strong>工具：</strong><br>- <strong>仿真引擎：</strong> Three.js 3D 渲染引擎、<br>- <strong>代码调测：</strong> vscode实时代码编辑器、数据双向同步智能体。 <br><strong>产出</strong><br>- <strong>数字资产：</strong> 基于 Three.js 开发的移动机器人生态 3D 数字孪生仿真控制系统源码。</td></tr><tr><td><strong>第十天</strong><br>多模态语音交互集成与轻量化结构优化<br></td><td><strong>上午</strong><br>- 系统集成：控制逻辑优化，<strong>全功能饱和测试</strong><br><strong>下午（14:00-17:10）：</strong><br>- <strong>轻量化设计与结构优化：</strong> 针对测试报告中暴露的问题，向 AI 提出轻量化与结构拓扑优化需求；由 AI 生成优化教程与减重应力分析，指导学生对机械底盘进行微调或零件更换。 <br>- <strong>产品化工艺最终定型：</strong> 开展最后一轮工业级线束收纳，杜绝一切“飞线”，进行车身总质检并由 AI 辅助撰写产品说明书。 <br><strong>工具</strong><br>- vscode，Autodesk fusion 360 generative design<br><strong>产出：</strong><br>- <strong>全功能代码：</strong> 完整合并的多模态（语音-视觉-网联）全系统综合控制代码包。 <br>- <strong>工程文档：</strong> 机器人全系统功能测试报告、AI 辅助产品拓扑优化说明书、工业级 README 文档。 <br>- <strong>实物成果：</strong> <strong>工艺精湛、结构深度优化、完美集成多模态语音与视觉交互的具身智能移动机器人终极原型机</strong></td></tr><tr><td>第十一天<br>包装</td><td>全面开展&quot;端-网-云-虚拟仿真&quot;压力测试；文档日志优化，web+视频优化，<br></td></tr><tr><td>第十二天<br>发布</td><td><strong>上午</strong><br>- 正式举办产品发布会，各小组轮流进行“5分钟技术路演 + 5分钟评审团 Q&amp;A”；<br>- 现场演示数字孪生虚拟实物双向任务协同。 专家评审<br><strong>下午：</strong><br>- 企业参访和企业专家演讲。 <br><strong>产出：</strong> 创新讲解视频、<strong>带走属于自己的第一台物理 AI 机器人及多方联合认证结营证书</strong>。</td></tr></tbody></table><h2 id="高中组-ai具身智能产品工程营" tabindex="-1">高中组：AI具身智能产品工程营 <a class="header-anchor" href="#高中组-ai具身智能产品工程营" aria-label="Permalink to &quot;高中组：AI具身智能产品工程营&quot;">​</a></h2><ul><li><p>从“单点生成”到“多智能体协作流（Multi-Agent Workflow）”</p><ul><li><p><strong>教学范式转移：</strong> 打破“输入提示词、生成单点结果”的线性黑盒体验 。高中组教学全面引入“专家智能体编排体系” 。</p></li><li><p><strong>学生角色演进：</strong> 引导学生理解并操纵“基于状态机的多Agent异步协同” ，通过飞书敏捷看板调度机械、硬件、代码、算法等多个专项AI Agent，实现从单纯的“工具操作员”向工业级“全栈系统架构师”的跨越。</p></li></ul></li><li><p>白盒机理破局黑盒生成——践行“硬件统一，AI赋能”</p><ul><li><p><strong>技术冲突消解：</strong> 完美调和传统代码/电路硬核数理公式与AI零代码降维工具之间的边界冲突 。</p></li><li><p><strong>逆向工作流重构：</strong> 独创“AI生成复杂要素 $\\rightarrow$ 学生进行白盒机理剖析 $\\rightarrow$ 仿真验证 $\\rightarrow$ 物理实操重构”的逆向工程流。AI负责降维琐碎的底层语法编译和物理接线验证 ，从而释放 <strong>70% 的高价值时间</strong>，让学生专注于运动学反解、有限状态机构建及全局技术拓扑的设计与推导。</p></li></ul></li><li><p>工业级“敏捷硬件开发”与“学术诚实性交付”</p><ul><li><p><strong>跨学科协同形态：</strong> 采用现代软件工程的“精锐双人组 + 数字化AI队友”敏捷开发范式 ，模拟真实工业研发的大兵团作战生态 。</p></li><li><p><strong>成果硬核对齐：</strong> 拒绝流水账式的传统流营日记 。学生最终交付的必须是包含<strong>数理公式推导、定量分析图表、Git Commit全留痕证据链</strong>的学术型开源作品集，精准对齐中国新工科战略及国家高素质科创人才鉴定标准。</p></li></ul></li><li><p>在打通“端-网-云-虚拟仿真”的完整产品全周期闭环基础上，全面注入<strong>系统工程（System Engineering）思维</strong>与<strong>学术严谨性</strong>，协助学生锻造出真正符合国内综评/强基计划及海外顶尖名校申请标准的<strong>工业级项目</strong> 。</p></li><li><p><strong>高中与初中组的本质区别</strong>：</p><ul><li><p>初中组：&quot;AI做所有事，学生只做决策&quot;</p></li><li><p>高中组：&quot;AI做基础执行，学生做系统设计和深度决策&quot;</p></li></ul></li></ul><table tabindex="0"><thead><tr><th><strong>日期与主题</strong></th><th><strong>内容（上午，下午，工具，产出）</strong></th></tr></thead><tbody><tr><td>第一天： <br>社会痛点与<br>商业可行性<br></td><td><strong>上午</strong><br>- 主题分享机制： FabLab 精神、AI时代跨学科教育及软硬件全新开发流程，引导学生以产品经理思维定义移动机器人；<br>- 需求头脑风暴： 学生自主列出校园、家庭或社区中真实存在的 10 个不便问题（100%学生决策）；指挥 AI 针对校园场景拓展生成 30 个潜在不便问题清单（100% AI执行）；<br>- 痛点深度剖析： 讨论并投票选出 5 个最有价值的问题，运用“用户-场景-痛点”模板进行解构；由 AI 对应生成精准的用户画像与具体场景描述。<br><strong>下午</strong><br>- 精锐团队组建： 明确“双人精锐组”为最小研发单元并完成现场组建，同步进行飞书项目管理工具入门；<br>- 引导学生拆解联合国可持续发展目标（SDGs），利用大模型进行行业级专利检索与分析，从现有竞品中提炼技术壁垒与痛点<br>- 利用大模型生成商业可行性与市场规模分析报告。团队完成飞书敏捷项目管理看板的搭建与首轮任务分解。<br>- 产品概念初探： 学生定义产品的核心功能目标；由 AI 辅助进行 Prompt 角色约束、起名、撰写 Slogan 及产品核心定位建议，并初步开展文生图外观脑暴。 <br><strong>工具</strong><br>- 通义千问 / Kimi / DeepSeek / MiniMax / 豆包 ；专利检索<br>- 协同协同： 飞书文档、看板 <br><strong>产出</strong><br>包含SDG定位、商业规模估算与竞品重构的高级PRD（产品需求文档）草稿、飞书项目任务分解图，创意脑暴海报</td></tr><tr><td>第二天： 功能定义</td><td><strong>上午</strong><br>- 提示词工程进阶： 学习提示词三要素（目标、要求、约束）以掌握高效向 AI 提需求的技巧；由 AI 针对性生成 5 个提示词场景练习题供学生实战训练。 <br>- 站在架构师角度建立具身智能机器人的“端-网-云-虚拟仿真”全局技术拓扑图<br>- 概念外观与生图迭代： 学生自主描述产品外观（颜色、形状、大小、材质）并手绘草图；指挥 AI 连续进行 3 次以上的文生图交互迭代，生成 5 张不同风格的机器人概念效果图。 指挥 AI 生成底盘、电机、摄像头、主控板的硬件科普视频<br>下午<br>- 学生深度审核并确认PRD终稿。<br>- web搭建，配置GitHub版本控制系统，规范“学术诚实性日志”的首次 Commit 规范，<br>- 搭建任务看板<br><strong>工具</strong><br>- AI 创作端： 大模型（DeepSeek/Kimi/Qwen等）、文生图工具、AI 视频/图文生成智能体。 <br>- 工程开发： VS Code、Gitee/github <br>- 协作管理： 飞书文档<br><strong>产出</strong><br>正式上线的团队与项目介绍网页，工业级标准最终版 PRD 文档，包含设计文件（ 提示词练习作业、机器人外观概念图、用户使用流程图） ，和工程文档</td></tr><tr><td>第三天：<br>参数化结构设计</td><td><strong>上午</strong> <br>- <strong>设计规范导临：</strong> 进行创客实验室安全培训，学习工业级 CMF（颜色、材质、工艺）与 DFM（可制造性设计）基础规范，理解“为加工而设计”的原则；<br>- <strong>结构体系认知：</strong> 建立对机器人空间机械结构的感性认知；指挥 AI 快速生成手办及结构概念示意；<br>- <strong>参数化建模决策：</strong> 理顺建模工具冲突，通过sophicar.com进行移动机器人的参数化设计；<br><strong>下午</strong><br>- <strong>三维模型终审：</strong> 学生从结构稳定性、整机重量、美观度三个维度对 AI 方案进行横向对比与关键选型决策；<br>- <br><strong>工具</strong><br>- <strong>模型生成：</strong> sophicar.com、Fusion 360 AI 脚本；<br>- <strong>三维渲染：</strong> 腾讯混元、Tripo 3D、MakerLab 等 AI 三维生成工具； <br><strong>产出</strong><br>- <strong>数字资产：</strong> 包含 <code>.stl</code> 等标准格式的最终三维底盘结构模型文件；<br>- <strong>工程文件：</strong> 数字化制造应用探索与加工参数生成文档；</td></tr><tr><td>第四天： 数字制造</td><td>- <strong>数字化加工实操：</strong> 操作数字制造设备，使用 FDM 3D 打印机、激光切割机等，将 AI 导出的最终模型文件加工转化为通电可用的物理实物零件。 <br>- 引导学生利用AI智能体进行工业级BOM（物料清单）成本优化，核算供应链采购最优价，撰写供应链优化报告<br>- <strong>工具：</strong> FDM 3D 打印机、激光切割机，激光雕刻机等<br>- <strong>产出：</strong> 加工完成的物理机器人外壳与底盘硬件，BOM</td></tr><tr><td>第五天：嵌入式基础<br></td><td><strong>内容</strong><br>- 以ESP32-S3核心开源硬件为基础，深入分析电路原理与元器件引脚选型，专注于“懂逻辑、明机理”<br>- 运动学反解。AI生成底座控制Python代码，学生负责推导公式并在Wokwi虚拟仿真平台中完成接线与反解校验。<br>工具：<br>- ESP32-S3核心板,Wokwi虚拟仿真平台<br>产出：移动机器人的基础运动（底盘）</td></tr><tr><td>第六天<br>机械臂与简单传感器融合</td><td>上午<br>- 打通主控板与电机、驱动器间的CAN总线与高频串口通信。聚焦产品化美感，进行高标准工艺线束收纳，杜绝“飞线”。<br>下午<br>- 了解机械臂逻辑，进行控制<br>- 由AI辅助进行多传感器融合方案设计（IMU+编码器+超声波传感器等）。<br><strong>工具</strong><br>- <strong>AI 协同开发：</strong> vscode、** Aily Blockly；**<br>- <strong>工程调测设备：</strong> 通用螺丝刀及理线模块套装、万用表、可调电源供应器；<br>- <strong>嵌入式总线：</strong> ESP32、CAN 总线扩展模块、串口驱动器。 <br><strong>产出：</strong><br>- 完整通电运行的物理样机、能硬件测试报告、故障排查与结构微调日志</td></tr><tr><td>第七天<br>全栈 Vibe Coding</td><td>上午<br>- <strong>零代码界面构建：</strong> 彻底跳过繁琐的 UI 代码编写，学生通过纯自然语言与 AI 对话进行全栈 Vibe Coding（100%学生决策）；指挥 AI 自动编译出美观的 HTML 网页或小程序交互控制界面，包含前进、后退、左转、右转和停止按钮（100% AI执行），同时预留摄像头、threejs位置 <br>下午<br>- 学生在AI指导下部署并配置边缘控制通信链，通过MQTT/WiFi协议将前端网页控制端与机器人主控板进行长连接跨网桥接。 <br><strong>工具：</strong><br>- <strong>界面编译：</strong> VS Code 插件、HTML5/CSS/JavaScript ，MQTT<br>- <strong>通信协议：</strong> 本地 Wi-Fi 通信模块、蓝牙 BLE 桥接组件。 <br><strong>产出：</strong><br>- <strong>数字资产：</strong> 跨平台前端控制网页/小程序全套源码包、AI 对话控制接口配置文档。 <br>- <strong>实物成果：</strong> <strong>成功实现 HTML/小程序跨网无线控制的移动机器人交互终端</strong>。</td></tr><tr><td>第八天<br>交互</td><td>- 利用视觉语言模型（VLM）将多模态提问（语音、画面）深度转化为机器人的结构化JSON动作指令流<br>- 描述完整的产品多模态工作流需求（100%学生决策）；指挥 AI 将语音控制、视觉识别、基础网页控制及避障算法代码深度合并，全自动生成单一、完整的集成系统代码，实现“听到指令出发、看到特定障碍物精准刹车/倒垃圾”的智能化作业逻辑（100% AI执行）<br>工具：Qwen VLM，YOLO，Hugging Face，Aily Blockly<br>产出：完成交互控制逻辑</td></tr><tr><td><strong>第九天</strong><br>数字孪生<br></td><td><strong>上午</strong><br>- 理解“虚拟仿真实体部署”系统集成方法。由AI辅助驱动高精度3D虚拟车模型的物理引擎与渲染框架。<br><strong>下午</strong><br>- 通过AI协助部署的高频双向同步逻辑，实现“滑块调整/物理实物运动 $\\rightarrow$ 3D虚拟车屏幕动画同步”的实时双向联动演示。<br><strong>工具：</strong><br>- <strong>仿真引擎：</strong> Three.js 3D 渲染引擎、<br>- <strong>代码调测：</strong> vscode实时代码编辑器、数据双向同步智能体。 <br><strong>产出</strong><br>- <strong>数字资产：</strong> 基于 Three.js 开发的移动机器人生态 3D 数字孪生仿真控制系统源码。<br>- <strong>核心成果：</strong> <strong>打通“端-网-云-虚拟仿真”的高维具身智能移动机器人控制演示系统</strong>。</td></tr><tr><td><strong>第十天</strong><br>多模态语音交互集成与轻量化结构优化<br></td><td><strong>上午</strong><br>- 系统集成：控制逻辑优化，<strong>全功能饱和测试</strong><br><strong>下午（14:00-17:10）：</strong><br>- <strong>轻量化设计与结构优化：</strong> 针对测试报告中暴露的问题，向 AI 提出轻量化与结构拓扑优化需求；由 AI 生成优化教程与减重应力分析，指导学生对机械底盘进行微调或零件更换。 <br>- <strong>产品化工艺最终定型：</strong> 开展最后一轮工业级线束收纳，杜绝一切“飞线”，进行车身总质检并由 AI 辅助撰写产品说明书。 <br><strong>工具</strong><br>- vscode，Autodesk fusion 360 generative design<br><strong>产出：</strong><br>- <strong>全功能代码：</strong> 完整合并的多模态（语音-视觉-网联）全系统综合控制代码包。 <br>- <strong>工程文档：</strong> 机器人全系统功能测试报告、AI 辅助产品拓扑优化说明书、工业级 README 文档。 <br>- <strong>实物成果：</strong> <strong>工艺精湛、结构深度优化、完美集成多模态语音与视觉交互的具身智能移动机器人终极原型机</strong></td></tr><tr><td>第十一天<br>包装</td><td>内容<br>- 全面开展&quot;端-网-云-虚拟仿真&quot;压力测试；文档日志优化，web+视频优化，<br>- 全面整理开源代码仓库，优化工业级README文档，提炼Git Commit历史记录以作为全栈团队协作与学术诚实性的铁证。<br>工具：GitHub Pages,Markdown 编辑器,Git Log 分析工具<br>产出：包含数理公式与定量分析图表的学术型技术报告、完全规范开源的GitHub技术仓库、Git Commit记录看板</td></tr><tr><td>第十二天<br>发布</td><td><strong>上午</strong><br>- 正式举办产品发布会，各小组轮流进行“5分钟技术路演 + 5分钟评审团 Q&amp;A”；<br>- 现场演示数字孪生虚拟实物双向任务协同。 专家评审<br><strong>下午：</strong><br>- 企业参访和企业专家演讲。 <br><strong>产出：</strong> 创新讲解视频、<strong>带走属于自己的第一台物理 AI 机器人及多方联合认证结营证书</strong>。</td></tr></tbody></table><h1 id="产出描述" tabindex="-1">产出描述 <a class="header-anchor" href="#产出描述" aria-label="Permalink to &quot;产出描述&quot;">​</a></h1><h2 id="实物项目" tabindex="-1">实物项目 <a class="header-anchor" href="#实物项目" aria-label="Permalink to &quot;实物项目&quot;">​</a></h2><p>带走属于你的第一台物理AI移动机器人</p><h2 id="网页和开源社区仓库-github-gitee" tabindex="-1">网页和开源社区仓库（GitHub / Gitee） <a class="header-anchor" href="#网页和开源社区仓库-github-gitee" aria-label="Permalink to &quot;网页和开源社区仓库（GitHub / Gitee）&quot;">​</a></h2><ul><li><p>建立网页和github仓库</p></li><li><p>工程日志：</p><ul><li><p>严禁记流水账。必须采用标准的科学记录格式：<strong>[面对的工程问题] → [原始数据/Bug 表现] → [给 AI 的 Prompt 迭代] → [AI 提供的解决方案] → [物理世界验证结果与反思]</strong>。</p></li><li><p>包含数理公式（如运动学方程）与定量分析图表，向评委展示极强的学术诚实性（Academic Integrity）与面对失败的工程韧性。</p></li><li><p>参考fab文档作业</p></li></ul></li><li><p>仓储内包含：完整的小车底层代码（带详尽注释）、Agent 提示词系统（Prompt System）、前端控制界面的源码以及 3D 打印的 <code>.STL</code> 结构文件。</p></li><li><p><strong>含金量体现：</strong> 规范的 Git Commit 记录是向世界名校证明学生具备真实团队协作、分布式开发能力的最佳证据。</p></li></ul><h2 id="视频" tabindex="-1">视频 <a class="header-anchor" href="#视频" aria-label="Permalink to &quot;视频&quot;">​</a></h2><ul><li><p>参考 Kickstarter 众筹视频或顶级实验室 Demo 视频的规格。</p></li><li><p>学生必须亲自出镜，全英文或中文讲解机器人的创新点、核心算法逻辑以及 Agent 具身智能的演示。这不仅是升学面试中的杀手级视觉材料，更是学生跨学科素养的终极体现。</p></li></ul><h2 id="对工程项目角色里的理解" tabindex="-1">对工程项目角色里的理解 <a class="header-anchor" href="#对工程项目角色里的理解" aria-label="Permalink to &quot;对工程项目角色里的理解&quot;">​</a></h2><ul><li><p><strong>产品经理（PM）：</strong> 负责机器人的场景定义与人机交互。利用 提示词<strong>工程</strong> 撰写符合工业标准的 PRD，用 Nanobanana/image2进行机器人概念外形迭代，和seedance2做出效果动画。</p></li><li><p><strong>前端/交互工程师：</strong> 利用 AI 代码工具，快速生成web进行内容展示和控制机器人</p></li><li><p><strong>后端与算法工程师（后端）：运动控制、路径规划与大模型 Agent 接口打通。</strong></p></li><li><p>嵌入式软件硬件工程师：硬件选型和代码输入，进行实物的控制；</p></li><li><p>**机械工程师：**使用AI辅助设计物理底盘、数字化制造、电路连接与传感器对齐</p></li><li><p><strong>项目经理（PJM）/ 系统集成师：</strong> 负责软硬件对齐，管理团队的甘特图，确保机械结构、电路板、算法集成，同时撰写项目日志</p></li></ul><h2 id="证书" tabindex="-1">证书 <a class="header-anchor" href="#证书" aria-label="Permalink to &quot;证书&quot;">​</a></h2><ul><li><p>学校、企业，sophilab联合发布的证书</p></li><li><p>学校二级单位盖章，sophilab盖章，</p></li><li><p>企业导师/结营答辩评委亲笔签名</p></li></ul><h2 id="评估报告" tabindex="-1">评估报告 <a class="header-anchor" href="#评估报告" aria-label="Permalink to &quot;评估报告&quot;">​</a></h2><table tabindex="0"><thead><tr><th>评估维度</th><th>权重</th><th>评估标准</th></tr></thead><tbody><tr><td>AI 工具使用能力</td><td>25%</td><td>AI 工具的使用深度与广度、AI 辅助开发的效率、AI 生成内容的质量与创新性</td></tr><tr><td>FabLab 制造能力</td><td>25%</td><td>数字设计能力、制造工艺掌握程度、原型迭代次数与速度、硬件完成质量</td></tr><tr><td>项目完成度与创新性</td><td>30%</td><td>功能完成度、技术创新性、解决问题的实际价值、系统稳定性</td></tr><tr><td>开源与协作精神</td><td>20%</td><td>文档完整性、代码质量、开源贡献度、团队协作表现</td></tr></tbody></table><h1 id="专家agent协作体系" tabindex="-1">专家Agent协作体系 <a class="header-anchor" href="#专家agent协作体系" aria-label="Permalink to &quot;专家Agent协作体系&quot;">​</a></h1><p><img src="https://internal-api-drive-stream.feishu.cn/space/api/box/stream/download/authcode/?code=ZDczMjAxNTNjY2M5MmFhMmY0YzBkMmJkNWM1Mjg4ZDVfODJmYTdmNjE5ZTc0YWZhOGEzNjY5ZjU0NjU3OTAxZWJfSUQ6NzY0NjIyOTUxNzUxNzg1MTYxMF8xNzgwNDE3NDY4OjE3ODA1MDM4NjhfVjM" alt="Image"></p><p>智能体底层逻辑——&quot;基于状态的编排&quot;：任务拆解（教育专家Agent接收需求→拆解为9维度子任务）→知识供给（Sophi-Omni提供历史案例和技术文档）→协同执行（机械设计Agent给出底座尺寸→嵌入式硬件Agent推荐电池和驱动板→嵌入式软件Agent生成引脚定义→算法Agent给出参考代码→系统集成Agent检查联调）→能力评估。</p><table tabindex="0"><thead><tr><th>Agent角色</th><th>核心关注点</th><th>夏令营角色</th></tr></thead><tbody><tr><td>机械设计</td><td>结构强度、减重、参数化建模</td><td>提供3种底盘方案供学生决策</td></tr><tr><td>机械制造</td><td>DFM、BOM生成</td><td>提供加工建议和零件清单</td></tr><tr><td>嵌入式硬件</td><td>电路原理、元器件选型</td><td>提供接线图和安全说明</td></tr><tr><td>嵌入式软件</td><td>Vibe Coding、驱动编写</td><td>生成代码供学生审核</td></tr><tr><td>算法</td><td>PID调优、视觉识别</td><td>生成调参方案供学生选择</td></tr><tr><td>系统集成</td><td>连线管理、整机调试</td><td>提供联调检查清单</td></tr><tr><td>产品与市场</td><td>SDGs、竞品分析、商业模式</td><td>帮助PRD完善和市场定位</td></tr><tr><td>商业与成本</td><td>BOM成本、供应链</td><td>生成成本分析报告</td></tr><tr><td>研发与创新</td><td>技术创新点、专利趋势</td><td>提供创新点建议</td></tr><tr><td>教育专家</td><td>评估、心理监测、预警</td><td>全程监控学习效果和心理状态</td></tr></tbody></table><p>知识底座Sophi-Omni：自动采集→AI初筛→人工审核→注入RAG的漏斗式更新逻辑。</p><p>教育专家Agent详细：标准共建（北师大评价体系）→AI初评→专家审计→动态课表调度→情绪与压力监测（NLP语义感知+行为判定+分级干预）→综合能力评估（动态雷达图）→人机协作触发器。</p><hr><h1 id="运维与组织" tabindex="-1">运维与组织 <a class="header-anchor" href="#运维与组织" aria-label="Permalink to &quot;运维与组织&quot;">​</a></h1><ul><li><p>课程实行走读制（8:30-18:00），2周共12天</p></li><li><p>对于一个 10-15 人的高水平班型，最专业且高效的配置是 <strong>“1位核心主讲 + 1位全栈技术助教 + 1位运营兼教务助教”</strong></p></li></ul><h2 id="教学人员" tabindex="-1">教学人员 <a class="header-anchor" href="#教学人员" aria-label="Permalink to &quot;教学人员&quot;">​</a></h2><ul><li><p>项目管理人员：吴波，佟怡姗</p></li><li><p>名誉导师：白明，孙煦</p></li><li><p>主讲导师（2人）：</p></li><li><p>全栈助教（2人）：</p></li><li><p>运营与教务助教：北师大1人，佟怡姗</p></li><li><p>企业导师：姚再启（吉利），小米？，机器人端？</p></li><li><p>评委：董艳，白明，牛林清？，孙煦，</p></li></ul><h3 id="名誉导师" tabindex="-1">名誉导师 <a class="header-anchor" href="#名誉导师" aria-label="Permalink to &quot;名誉导师&quot;">​</a></h3><p>课程内容制定指导；指导学生研究方向和方法论</p><h3 id="主讲导师" tabindex="-1">主讲导师 <a class="header-anchor" href="#主讲导师" aria-label="Permalink to &quot;主讲导师&quot;">​</a></h3><ul><li><p><strong>角色定位：</strong> 他不需要精通每一行底层 C++ 代码，但他必须具备<strong>系统级工程视野</strong>。他负责讲授产品定义、Prompt 工程思维、Agent 架构逻辑，并主持每日站会（Daily Scrum）和结营答辩。</p></li><li><p><strong>能力画像：</strong> 拥有 FabLab/创客空间运营背景、高校机器人实验室（如 RoboMaster 导师/退役队长）背景，或是有过硬 PBL 教学经验的科技创新专家。</p></li><li><p><strong>核心任务：</strong> 掌控教学节奏，引导学生向 AI 正确提问，激发创造力，把控升学日志的学术严谨性。</p></li></ul><h3 id="全栈技术助教" tabindex="-1">全栈技术助教 <a class="header-anchor" href="#全栈技术助教" aria-label="Permalink to &quot;全栈技术助教&quot;">​</a></h3><ul><li><p><strong>角色定位：</strong> 负责解决 AI 工具无法完全替代的“物理世界物理 Bug”（如：虚焊、线束接错、3D 打印切片出错、硬件烧毁、网络端口不通）。</p></li><li><p><strong>能力画像：</strong> 计算机、电子、机械工程专业的高年级优秀本科生或研究生。</p></li><li><p><strong>核心任务：</strong> 维护实验室设备（3D 打印机/激光切割机），在学生利用 Cursor 编写代码卡壳时提供微调指导，确保顺利通关。</p></li></ul><h3 id="运营与教务助教" tabindex="-1">运营与教务助教 <a class="header-anchor" href="#运营与教务助教" aria-label="Permalink to &quot;运营与教务助教&quot;">​</a></h3><ul><li><p><strong>角色定位：</strong> 负责夏令营的后勤、日常耗材管理、敏捷看板物资准备，以及最重要的一点——<strong>家长端的内容输出与影像记录</strong>。</p></li><li><p><strong>核心任务：</strong> 拍摄学生造物过程的高清照片/视频；每日在家长群输出深度工程进展报告（。</p></li></ul><h2 id="组织方" tabindex="-1">组织方 <a class="header-anchor" href="#组织方" aria-label="Permalink to &quot;组织方&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>宁波</th><th>北京</th></tr></thead><tbody><tr><td>组织方</td><td>UNNC-BDO</td><td>北师大教育集团</td></tr><tr><td>定价 （人民币）</td><td>16800</td><td>19800</td></tr><tr><td>定价逻辑</td><td>依托浙东地区雄厚的制造业与创新土壤，主打“高科技小合伙人”和“国际化 FabLab 造物”概念，契合 UNNC 等国际化家庭的教育预算</td><td>北京海淀/朝阳高端科创营的标配区间。家长愿意为<strong>升学溢价</strong>买单；同时设备由宁波团队提供到北京需要额外成本</td></tr><tr><td>渠道分发</td><td></td><td></td></tr><tr><td>sophilab价格</td><td>12800</td><td>14800</td></tr><tr><td>组织方承担</td><td>招生渠道成本、场地水电使用费、学生及导师的午餐茶歇费、保险，交通大巴</td><td>招生渠道成本、场地水电使用费、学生及导师的午餐茶歇费、保险，交通大巴</td></tr><tr><td>sophilab承担</td><td>硬件套件的物料成本（BOM成本）、老师酬劳，软件授权费</td><td>硬件套件的物料成本（BOM成本）、老师酬劳，软件授权费，设备运输</td></tr><tr><td>收款账户</td><td>宁波诺丁汉大学</td><td>北师大教育集团</td></tr><tr><td>分成激励</td><td>- 单期10人内，不额外分成；<br>- 单期招满 12 人，Sophilab 增加返点800元每人；<br>- 单期招满 15 人满班，Sophilab 合计增加返点1000元每人；</td><td></td></tr><tr><td><strong>款项路径</strong></td><td>家长支付学费 $\\rightarrow$ <strong>组织方官方对公账户（全额收款并开票）</strong> $\\rightarrow$ 夏令营开营后 3 个工作日内 $\\rightarrow$ 组织方根据实际入营人数，向 Sophilab 支付 <strong>60% 的预付款</strong> $\\rightarrow$ 结营答辩通过后 5 个工作日内 $\\rightarrow$ 结算<strong>剩余尾款</strong>。</td><td></td></tr></tbody></table><h2 id="场地要求" tabindex="-1">场地要求 <a class="header-anchor" href="#场地要求" aria-label="Permalink to &quot;场地要求&quot;">​</a></h2><ul><li><p>网络要求： 必须具备高带宽、低延迟的无线网络（保障 15 人同时高频调用 LLM API 不卡顿）。</p></li><li><p>空间需求</p><ul><li><p>测试场地： 需要一个至少 6m $\\times$ 6m 的平整地面，用于铺设测试场景</p></li><li><p>数字加工区域：100平方， 数字加工区域需要供电（4-5kw），和良好的排风（尤其是激光切割异味较重）。</p></li><li><p>学习空间，60平方，需要理论学习和部分实操训练；每人一个1.2*2.4米桌子区域；</p></li><li><p>路演区域：演讲厅/会议厅等</p></li></ul></li></ul><h2 id="软件工具" tabindex="-1">软件工具 <a class="header-anchor" href="#软件工具" aria-label="Permalink to &quot;软件工具&quot;">​</a></h2><ul><li><p>其他参考</p><ul><li><p>fabacademy.org：课程内容</p></li><li><p>buleprint.am：提示词生成实物，BOM（含采购链接），拓扑逻辑</p></li><li><p><a href="https://yiyu" target="_blank" rel="noreferrer">https://yiyu</a>.pro/home：提供AI生成Arduino/ESP等开源硬件代码</p></li></ul></li></ul><h2 id="硬件工具" tabindex="-1">硬件工具 <a class="header-anchor" href="#硬件工具" aria-label="Permalink to &quot;硬件工具&quot;">​</a></h2><h1 id="政策与比赛" tabindex="-1">政策与比赛 <a class="header-anchor" href="#政策与比赛" aria-label="Permalink to &quot;政策与比赛&quot;">​</a></h1><h2 id="政策" tabindex="-1">政策 <a class="header-anchor" href="#政策" aria-label="Permalink to &quot;政策&quot;">​</a></h2><p>北京与浙江教育端相关政策及影响，两地的教育政策均向“科创与综合素质”倾斜，但选拔路径和侧重点有明显差异</p><h3 id="北京政策环境" tabindex="-1">北京政策环境 <a class="header-anchor" href="#北京政策环境" aria-label="Permalink to &quot;北京政策环境&quot;">​</a></h3><ul><li><p>核心政策：高中综合素质评价（综评）、强基计划 。</p></li><li><p><strong>政策现状</strong>：北京的高校（如清华、北大、北航、北理工等）在强基计划和综合评价的校测面试中，极为看重学生是否具备真正的科研潜质。</p></li><li><p><strong>证书与报告的切入点</strong>：北京营联合北师大二级学院，其盖章的评估报告能对应高中综评系统中的“研究性学习记录”。面试官在面对海淀区大量同质化的“考级证书”时，一份带有量化雷达图、数理公式以及北师大教育专家模型二次审计的评估报告，能完美证明项目的自主完成度。</p></li></ul><h3 id="浙江政策环境" tabindex="-1">浙江政策环境 <a class="header-anchor" href="#浙江政策环境" aria-label="Permalink to &quot;浙江政策环境&quot;">​</a></h3><ul><li><p>核心政策：三位一体招生（综评）、“强基计划”区域特化。</p></li><li><p><strong>政策现状</strong>：浙江是国内“三位一体”招生最成熟的省份，且浙大、西湖大学等高校对数字化造物、机器人等交叉学科极其青睐。</p></li><li><p><strong>证书与报告的切入点</strong>：宁波营由 UNNC-BDO 组织。利用 <strong>UNNC-FabLab 印章</strong> 能够产生极强的品牌剪刀差。浙江高校的考官非常清楚浙东制造业的数字化转型需求。报告中若强调“算法到实物的闭环转化（Sim-to-Real）” 和 “工业级版本控制” ，其含金量超过单纯的代码编写。</p></li></ul><h3 id="国内外大厂直招政策现实" tabindex="-1">国内外大厂直招政策现实 <a class="header-anchor" href="#国内外大厂直招政策现实" aria-label="Permalink to &quot;国内外大厂直招政策现实&quot;">​</a></h3><ul><li><p>明细：<a href="https://www.findyou2026.com/" target="_blank" rel="noreferrer">吉利：</a><a href="https://www.findyou2026.com/" target="_blank" rel="noreferrer">跨时代跃迁人才培养计划</a>，<a href="https://tcamp.qq.com/" target="_blank" rel="noreferrer">腾讯“青科实训营”</a></p></li><li><p>看重规则</p><ul><li><p>不要传统“做题家”，要解决复杂问题的“特才”。</p></li><li><p>看重“全栈造物能力”：你能不能用自然语言（Vibe Coding）配合大模型迅速跑通一个 Web 控制端？能不能解决端云一体化中 MQTT 丢包、网络抖动的物理世界 Bug？</p></li><li><p>极度看重学术诚实性（Academic Integrity）：你的工程日志是否规范？GitHub 上的 Commit 记录是否是你本人亲自提交并迭代的？</p></li></ul></li></ul><h2 id="比赛" tabindex="-1">比赛 <a class="header-anchor" href="#比赛" aria-label="Permalink to &quot;比赛&quot;">​</a></h2><ul><li><p>全国大学生机器人大赛（RoboMaster、RoboCon）</p></li><li><p>中国国际&quot;互联网 +&quot; 大学生创新创业大赛</p></li><li><p>&quot;挑战杯&quot; 全国大学生课外学术科技作品竞赛◦</p></li><li><p>青少年科技创新大赛</p></li><li><p>信息技术创新实践</p></li><li><p>Engineering Portfolio</p></li><li><p>Maker Portfolio</p></li><li><p>AI/CS Background</p></li><li><p>Robotics Research Interest</p></li><li><p>Summer Program Extension</p></li></ul><table tabindex="0"><thead><tr><th>名称</th><th>主题</th><th>主办单位</th><th>指导单位</th><th>白名单状态</th><th>对象</th><th>链接</th></tr></thead><tbody><tr><td>第九届全国青少年人工智能创新挑战赛</td><td>给梦想插上科技的翅膀</td><td>中国少年儿童发展服务中心（共青团中央直属事业单位）</td><td>中国计算机学会、中国科学院计算技术研究所、中国科学院软件研究所</td><td>入选教育部&quot;2025-2028学年面向中小学生的全国性竞赛活动&quot;名单</td><td>全国在校小学、初中、高中、中专、职高学生（6-18岁）</td><td><a href="http://aiic.china61.org.cn" target="_blank" rel="noreferrer">http://aiic.china61.org.cn</a></td></tr><tr><td></td><td></td><td></td><td></td><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><h1 id="场景应用表" tabindex="-1">场景应用表 <a class="header-anchor" href="#场景应用表" aria-label="Permalink to &quot;场景应用表&quot;">​</a></h1><table tabindex="0"><thead><tr><th>内容</th><th>北京</th><th>宁波</th></tr></thead><tbody><tr><td>主题</td><td>当AI机器人遇见世界文化遗产</td><td>当AI机器人遇见工业场景</td></tr><tr><td>SDGs</td><td>文化传承×具身智能×人机交互</td><td>智能制造×数字化造物×工业4.0</td></tr><tr><td>初中生</td><td>文生图+Agent将游客提问转JSON动作指令</td><td>模块化认知+vibe coding部署</td></tr><tr><td>高中生</td><td>多智能体协同+光照杂音干扰去除</td><td>控制调优+Generative Design拓扑优化</td></tr><tr><td>推送新闻</td><td>当大模型学会&quot;看&quot;世界文化遗产</td><td>未来工业合伙人：全栈物流机器人</td></tr></tbody></table><hr><h1 id="宣推策略-来自v3" tabindex="-1">宣推策略（来自v3） <a class="header-anchor" href="#宣推策略-来自v3" aria-label="Permalink to &quot;宣推策略（来自v3）&quot;">​</a></h1><ul><li>落地方式：通识课程(AI科普：公益讲座)， 实操课程（AI教学： 以移动机器人的为应用场景），进阶课程（竞赛、升学）</li></ul><p>由主讲导师领衔投稿至中国教育创客/STEAM教育相关期刊。激发家长朋友圈裂变与区域新闻网首发。媒体矩阵：高校教授+行业创客+车企专家评审团。宣发节奏：Day11盲测彩排放出&quot;3分钟应急备份演示视频&quot;先导预热；Day12通过组织方对公渠道邀请科技/教育类媒体现场报道。</p><hr><h1 id="核心冲突汇总" tabindex="-1">核心冲突汇总 <a class="header-anchor" href="#核心冲突汇总" aria-label="Permalink to &quot;核心冲突汇总&quot;">​</a></h1><table tabindex="0"><thead><tr><th>冲突项</th><th>v3立场</th><th>v6铁律立场</th><th>建议</th></tr></thead><tbody><tr><td>Day4代码理解</td><td>了解I/O、引脚、代码逻辑</td><td>完全不接触代码</td><td>理解工作原理≠写代码</td></tr><tr><td>Day3 Fusion360</td><td>学生操作Fusion360建模</td><td>纯AI生成，学生只选</td><td>高中组保留&quot;AI辅助&quot;</td></tr><tr><td>Day4电路原理</td><td>深入分析电路原理</td><td>只看接线图</td><td>高中组保留背景理解</td></tr><tr><td>Day5 PID调参</td><td>直接讲解PID公式</td><td>游戏化滑块调参</td><td>高中组保留公式背景</td></tr><tr><td>Day5 Python运动学</td><td>用Python做运动学反解</td><td>纯AI生成</td><td>AI生成Python，学生理解</td></tr><tr><td>Day4底层代码</td><td>AI协助生成C++/Python驱动</td><td>禁止代码接触</td><td>AI生成，学生审核逻辑</td></tr><tr><td>以上均需人工最终确认</td><td></td><td></td><td></td></tr></tbody></table><hr><h1 id="v3独有内容-v6deepseek框架中无对应章节-保留v3原文" tabindex="-1">v3独有内容（v6deepseek框架中无对应章节，保留v3原文） <a class="header-anchor" href="#v3独有内容-v6deepseek框架中无对应章节-保留v3原文" aria-label="Permalink to &quot;v3独有内容（v6deepseek框架中无对应章节，保留v3原文）&quot;">​</a></h1><h2 id="a-方向建议-v3-callout块" tabindex="-1">A. 方向建议（v3 callout块） <a class="header-anchor" href="#a-方向建议-v3-callout块" aria-label="Permalink to &quot;A\\. 方向建议（v3 callout块）&quot;">​</a></h2><p>学会大模型（国内模型），claude 生成结果。自然语言交互（高效沟通）。交互结果去部署。硬件支持功能实现：机电（现成），制作/标准件。软硬件联调的功能。AI辅助营销方案。从需求到结果，中间黑盒（对此有兴趣），类比大学生看arduino和语法。家长看兴趣，探索问题的方法，启蒙教育。中学生不同年龄的理解。</p><h2 id="b-课程设计核心理念" tabindex="-1">B. 课程设计核心理念 <a class="header-anchor" href="#b-课程设计核心理念" aria-label="Permalink to &quot;B\\. 课程设计核心理念&quot;">​</a></h2><p>在传统的机器人教育中，学生往往花费70%的时间在枯燥的语法纠错、环境配置和重复调试上。本课程的核心理念是&quot;硬件统一，AI赋能&quot;：AI并非一门独立的学科，而是工程落地的超级放大器。</p><p>在落地这套课程时，我们必须坚守一个核心教学原则：教师不是知识的灌输者，而是&quot;提示词导师&quot;。教导学生在AI时代如何正确地向机器提问，并勇敢地在物理世界中亲手将其实现——这正是这套课程跨越时代的教育魅力所在。</p><h2 id="c-v3原始待处理问题checklist" tabindex="-1">C. v3原始待处理问题checklist <a class="header-anchor" href="#c-v3原始待处理问题checklist" aria-label="Permalink to &quot;C\\. v3原始待处理问题checklist&quot;">​</a></h2><ul><li><p>[ ] 如何配置老师：需要有全栈的专业能力</p></li><li><p>[ ] 定价策略与分发渠道：外部价格，分成机制，成本</p></li><li><p>[ ] 学校作为分发渠道的合理性：招生不满的对策</p></li><li><p>[ ] 如何寻找学生：参与人有基础，能区分内容，和逻辑框架</p></li><li><p>[ ] 如何在硬件上实施：claude控制pc端软件？</p></li><li><p>[ ] 利用AI教解决问题：产品经理给prompt，AI给出资源，产品经理操作部署</p></li><li><p>[ ] AI在机械设计的边界</p></li><li><p>[ ] AI工作流如何让学生入门</p></li></ul><h2 id="d-ai工作流思考-来自v3讨论区" tabindex="-1">D. AI工作流思考（来自v3讨论区） <a class="header-anchor" href="#d-ai工作流思考-来自v3讨论区" aria-label="Permalink to &quot;D\\. AI工作流思考（来自v3讨论区）&quot;">​</a></h2><ul><li><p>三个飞书知识库协同工作：fab（课程+CMF+AI教育）/ sophicar（参数化设计+移动机器人）/ ProFabX（工程模型+供应链）</p></li><li><p>Sophi studio为三者中枢</p></li><li><p>工作流：知识库文档 → agent编排 → 大模型选择（教育端国产模型 vs 行业端gemini/chatgpt/claude code）</p></li></ul><hr><p>*本文档以v6deepseek框架为基底，完整保留v3全部内容。v3内容用蓝色标注，冲突用红色标注，未做任何删除。AIGC生成于2026-05-31。*</p><h1 id="问题" tabindex="-1">问题 <a class="header-anchor" href="#问题" aria-label="Permalink to &quot;问题&quot;">​</a></h1><ul><li><p>[x] 内容合理性，初高中如何分开</p></li><li><p>[x] 政策：中考，高考，出国的政策基础</p></li><li><p>[ ] 如何配置老师，老师寻找：需要有全栈的专业能力；</p></li><li><p>[ ] 定价策略与分发渠道</p></li><li><p>[ ] 学校作为分发渠道的合理性：招生不满的对策</p></li><li><p>[ ] 如何寻找学生：参与人有基础，能区分内容，和逻辑框架</p></li><li><p>[ ] 如何在硬件上实施：claude 控制pc端软件？</p></li><li><p>[ ] 利用AI教解决问题：产品经理给prompt，AI给出资源，产品经理操作部署（AI指导）；问题拆分形成产品需求文档</p></li><li><p>[ ] AI的图文（人工辅助）指导学生做加工</p></li><li><p>[ ] AI在机械设计的边界</p></li><li><p>[ ] AI工作流如何让学生入门</p></li><li><p>[ ] 初高中切开</p></li><li><p>[ ] 升学</p></li><li><p>[ ] 商业回报</p></li><li><p>[ ] 合作方式</p></li></ul>',103)])])}const u=r(i,[["render",d]]);export{p as __pageData,u as default};
